```go
// Test skeleton: internal/kernel/sharedlayer/state_store_test.go

func TestMemoryStateStore_ConcurrentSaveLoad(t *testing.T) {
    store := NewMemoryStateStore()
    state := types.TaskState{
        Task:      &types.AgentTask{TaskID: "test-1"},
        UpdatedAt: time.Now(),
    }

    var wg sync.WaitGroup
    for i := 0; i < 100; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            store.Save(fmt.Sprintf("task-%d", id), state)
        }(i)
    }
    wg.Wait()

    // Verify all saves succeeded
    for i := 0; i < 100; i++ {
        _, err := store.Load(fmt.Sprintf("task-%d", i))
        if err != nil {
            t.Errorf("Failed to load task-%d: %v", i, err)
        }
    }
}

func TestMemoryStateStore_DeleteNonExistent(t *testing.T) {
    store := NewMemoryStateStore()
    err := store.Delete("non-existent")
    if err != nil {
        t.Errorf("Delete on non-existent key should not error: %v", err)
    }
}
