// Test skeleton: internal/kernel/lifecycle/lifecycle_test.go

func TestLifecycleManager_ImmediateCancel(t *testing.T) {
    ctx, cancel := context.WithCancel(context.Background())
    cancel() // Cancel immediately

    mgr := NewLifecycleManager()
    mgr.monitorContext(ctx)

    if mgr.IsRunning() {
        t.Error("Should not be running after context cancel")
    }
}

func TestLifecycleManager_IsRunningDuringShutdown(t *testing.T) {
    mgr := NewLifecycleManager()

    ctx, cancel := context.WithCancel(context.Background())
    go func() {
        time.Sleep(10 * time.Millisecond)
        cancel()
    }()

    mgr.Shutdown(ctx)

    // Give goroutine time to process
    time.Sleep(50 * time.Millisecond)
    if mgr.IsRunning() {
        t.Error("Should not be running after shutdown completes")
    }
}
