// Test skeleton: internal/kernel/orchestrator/orchestrator_integration_test.go

func TestOrchestrator_Integration_GracefulShutdownDuringExecution(t *testing.T) {
    orch := NewOrchestrator(
        WithModelProvider(provider.NewMockModelProvider()),
    )
    ctx := context.Background()

    // Register a slow contract
    orch.RegisterContract(&types.AgentContract{
        ContractID: "slow",
        InputSchema: &types.InputSchema{
            Fields: []types.FieldDef{{Name: "x", Type: types.FieldTypeString, Required: true}},
        },
    })

    // Start orchestrator
    orch.Start(ctx)

    // Submit task
    orch.SubmitTask(&types.AgentTask{
        TaskID:     "slow-task",
        ContractID: "slow",
        Input:      map[string]any{"x": "y"},
        Metadata:   map[string]string{types.SLAKeyTimeoutMs: "60000"},
    })

    // Give task time to start
    time.Sleep(100 * time.Millisecond)

    // Shutdown should complete without hanging
    shutdownCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()

    err := orch.Shutdown(shutdownCtx)
    if err != nil {
        t.Fatalf("Shutdown timed out: %v", err)
    }
}

func TestOrchestrator_Integration_DAGExecution(t *testing.T) {
    orch := NewOrchestrator()
    ctx := context.Background()

    orch.RegisterContract(&types.AgentContract{
        ContractID: "default",
        InputSchema: &types.InputSchema{
            Fields: []types.FieldDef{{Name: "x", Type: types.FieldTypeString, Required: true}},
        },
    })

    orch.Start(ctx)

    // A -> B -> C dependency chain
    orch.SubmitTask(&types.AgentTask{
        TaskID:     "A",
        ContractID: "default",
        Input:      map[string]any{"x": "a"},
    })
    orch.SubmitTask(&types.AgentTask{
        TaskID:         "B",
        ContractID:     "default",
        Input:          map[string]any{"x": "b"},
        Dependencies:    []string{"A"},
    })
    orch.SubmitTask(&types.AgentTask{
        TaskID:         "C",
        ContractID:     "default",
        Input:          map[string]any{"x": "c"},
        Dependencies:    []string{"B"},
    })

    // Wait for completion
    deadline := time.Now().Add(10 * time.Second)
    for time.Now().Before(deadline) {
        status, _ := orch.GetTaskStatus("C")
        if status == types.TaskStatusCompleted {
            return // Success
        }
        time.Sleep(50 * time.Millisecond)
    }

    t.Fatal("Task C did not complete in time")
}
```

